#include <stdio.h>
#include <stdint.h>

// S-box for AES (substitution)
static const uint8_t sbox[256] = {
    0x63, 0x7c, 0x77, 0x7b, 0xf2, 0x6b, 0x6f, 0xc5,
    // ... (full S-box would be here)
};

// Round constants
static const uint8_t Rcon[11] = {
    0x8d, 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80, 0x1b, 0x36
};

// RotWord: circular left shift of 4-byte word
uint32_t rotWord(uint32_t w) {
    return ((w << 8) | ((w >> 24) & 0xff));
}

// SubWord: apply S-box to each byte
uint32_t subWord(uint32_t w) {
    uint8_t *p = (uint8_t *)&w;
    p[0] = sbox[p[0]];
    p[1] = sbox[p[1]];
    p[2] = sbox[p[2]];
    p[3] = sbox[p[3]];
    return w;
}

// Key expansion for AES-128 (generates 44 32-bit words)
void keyExpansion(const uint8_t *key, uint32_t w[44]) {
    // First 4 words are the key
    for (int i = 0; i < 4; i++) {
        w[i] = (key[4*i] << 24) | (key[4*i+1] << 16) | 
               (key[4*i+2] << 8) | key[4*i+3];
    }

    // Generate remaining 40 words
    for (int i = 4; i < 44; i++) {
        uint32_t temp = w[i-1];
        if (i % 4 == 0) {
            temp = subWord(rotWord(temp)) ^ Rcon[i/4];
        }
        w[i] = w[i-4] ^ temp;
    }
}

int main() {
    uint8_t key[16] = {0x2b, 0x7e, 0x15, 0x16, 0x28, 0xae, 0xd2, 0xa6,
                       0xab, 0xf7, 0x15, 0x88, 0x09, 0xcf, 0x4f, 0x3c};
    uint32_t w[44];
    keyExpansion(key, w);
    printf("AES-128 Key Expansion Complete\n");
    return 0;
}

import javax.crypto.Cipher;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;

public class CTRModeEncryption {

    // Increment counter array by 1
    private static byte[] incrementCounter(byte[] counter) {
        for (int i = counter.length - 1; i >= 0; i--) {
            if (++counter[i] != 0) break;
        }
        return counter;
    }

    public static byte[] ctrEncrypt(byte[] plaintext, byte[] key) throws Exception {
        // AES uses 128-bit (16-byte) blocks
        int blockSize = 16;

        // Generate random 16-byte nonce/IV
        byte[] nonce = new byte[blockSize];
        new SecureRandom().nextBytes(nonce);

        // Initialize cipher for AES
        SecretKeySpec keySpec = new SecretKeySpec(key, "AES");
        Cipher cipher = Cipher.getInstance("AES/ECB/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, keySpec);

        byte[] ciphertext = new byte[plaintext.length];
        byte[] counter = nonce.clone();
        byte[] keystream = new byte[blockSize];

        for (int i = 0; i < plaintext.length; i += blockSize) {
            // Generate keystream block
            keystream = cipher.doFinal(counter);

            // XOR plaintext with keystream
            int remaining = Math.min(blockSize, plaintext.length - i);
            for (int j = 0; j < remaining; j++) {
                ciphertext[i + j] = (byte)(plaintext[i + j] ^ keystream[j]);
            }

            // Increment counter
            counter = incrementCounter(counter);
        }

        // Prepend nonce to ciphertext for decryption
        byte[] result = new byte[nonce.length + ciphertext.length];
        System.arraycopy(nonce, 0, result, 0, nonce.length);
        System.arraycopy(ciphertext, 0, result, nonce.length, ciphertext.length);

        return result;
    }

    public static void main(String[] args) throws Exception {
        byte[] key = new byte[32]; // 256-bit key
        new SecureRandom().nextBytes(key);

        byte[] plaintext = "Hello CTR Mode!".getBytes();
        byte[] encrypted = ctrEncrypt(plaintext, key);
        System.out.println("Encryption successful, length: " + encrypted.length);
    }
}
